INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00119', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '下列關於甲於2024年1月1日所立遺囑之效力敘述，何者正確？ 甲為2005年12月31日出生，其遺囑無效 甲為2008年12月31日出生，其遺囑有效 甲為2007年5月31日出生，所立遺囑未經其法定代理人同意，其遺囑無效 甲為2007年12月31日出生，其法定代理人拒絕承認甲所立遺囑，其遺囑無效', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00120', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '下列關於特留分之敘述，何者正確？ 繼承人喪失繼承權，但仍享有特留分 繼承開始後，特留分權利不得自由拋棄 拋棄特留分，不等於拋棄繼承 拋棄特留分後，其他特留分權利人之特留分當然因而增加', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00121', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '科學園區某甲公司欲申請設立新製程之晶圓廠，因而向 A市政府申請建
照，該管機關之處分如下，其合法性如何？（25分）
申請案核准，但要求甲須於期限內做好污水回收處理設備。
甲須捐贈該市文化基金新臺幣2000萬元，方允許設立新廠房。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "4696b78838fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00122', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '甲公司（以下簡稱甲）係外籍看護工之仲介業者，替乙女士辦理聘僱外
籍看護工相關事宜。惟甲在該看護工受僱期間，於其薪資內以「本國所
得稅」、「安家費貸款」等名目，超收規定標準以外的其他費用，合計新
臺幣（下同）10萬元。該案經媒體揭露並引發社福團體關注，A縣政府
（以下簡稱 A）遂根據就業服務法第 40 條第 1 項第 5 款之規定，以甲所
收受之不正利益10 萬元為基礎，處以同法第 66條第 1 項規定（10至 20
倍）的最高額度罰鍰，即200萬元罰鍰。
甲以 A於該處分中，未明白表示其處以最高 20倍罰鍰之理由，有違「明
確性原則」，並主張 A 未曾訂定相關裁罰基準，只為應付輿論壓力，對
於初犯者處以最高罰鍰，不符裁量原則。甲之主張是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "4696b78838fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00123', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '我國「行政執行法」對於行政法上「行為或不行為之義務」有其直接與
間接的強制手段。請就相關規定由輕而重，分析行政執行之執行種類以
及機關可採之執行方法。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "4696b78838fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00124', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '近年國人熱衷於郊山健走與溯溪等親近大自然的活動，對於自然環境設
施之利用頻率增加。但也因山林、水域幅員廣大，加上自然保育之要求，
整建不宜加諸過多的人工干預設施。今有甲自行沿野溪旁之步道健走，途
中遇午後雷雨溪水上漲，因恐山洪暴發無法通行，遂強行渡過攔砂壩折
返。惟甲於半渡之時失足滑落，且頭部撞擊溪石導致昏迷，其後又因溪水
暴漲溺水死亡。甲之家屬認為該步道既然開放給公眾使用，即應具有足夠
的安全設施，故對步道負有管理權責之鄉公所A（以下簡稱A）提出國家
賠償請求。A認為攔砂壩乃水利機關所設，並非步道之附屬設施，鄉公所
並非負責機關。且其設置目的在阻擋砂石，平日雖亦有民眾抄捷徑通行，
但 A 已在兩端設置警告標誌。又甲於溪水暴漲時仍強行渡河，乃自陷危
險，故主張國賠責任不成立。請問本案是否應成立國家賠償？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "4696b78838fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00125', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'essay', '甫上小學的 A，過年期間隨父母回臺南祖父母家過年，除了祖父母外，
眾多親戚長輩都慷慨給予紅包。過年期間親友往來頻繁，就讀大學的 B
隨父母到 A祖父母家拜年，大人閒聊時，B覺無趣，遂想去陪 A遊玩。
見 A正拿出壓歲錢一張一張數著玩，B心生一計，掏出為了去日本旅遊
而換的日幣萬元紙鈔，對 A 說：「這麼多張紙鈔很厚，帶起來好麻煩，
不如拿 10張千元鈔，跟我換這張萬元鈔，這樣就不用帶這麼厚了。」A
不懂分辨不同國家幣值，亦不知新臺幣並無萬元鈔，見紙鈔上的 10000
字樣，算了算數，的確是 10 個 1,000，便同意拿 10 張千元鈔與 B 的日
幣萬元鈔交換。請問 B的行為該如何評價？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00126', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'essay', 'A 到 B 家向 B 追討之前借給 B 的錢，沒想到 B 不但不還，還嘲諷 A 是
守財奴，才這麼點錢還急著追討。A盛怒之下，隨手拿起手邊的馬克杯，
邊叫囂要 B閉嘴，邊拿馬克杯猛力朝 B 太陽穴部位敲擊數次，B 頭部頓
時血流如注，失去意識倒地不起。A見狀連忙逃跑，待心緒稍定後打給
自己的女友 C，告知全情，C勸 A 應該立刻叫救護車救 B，A因害怕便
叫 C打電話叫救護車至 B家救 B。孰知，B因家人返家，在 C叫的救護
車抵達之前，就已經送醫診治獲救。請問 A的行為該如何評價？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00127', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於擄人勒贖罪，下列敘述何者錯誤？', '["意圖勒贖而擄人者屬之", "擄人後意圖勒贖者屬之", "如故意使人受重傷者，得處死刑", "如致人受重傷者得處死刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00128', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '處罰之裁判確定後，未執行或執行未完畢，而法律有變更，不處罰其行為者，依刑法之規定，其 效果為何？', '["其刑之宣告以已廢止論", "其刑之宣告以已執行論", "另由法務部長以行政處分赦免之", "免其刑之執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
